// SQL排序字段白名单
const ALLOWED_SORT_FIELDS = [
  'id', 'iteration_number', 'status', 'started_at', 
  'created_at', 'updated_at', 'duration_seconds'
];

// 允许的排序方向
const ALLOWED_SORT_DIR = ['ASC', 'DESC'];

/**
 * 验证并清理排序参数
 */
export function validateSortParam(sort: string | undefined): { field: string; dir: string } | null {
  if (!sort) return null;

  const field = sort.startsWith('-') ? sort.slice(1) : sort;
  const dir = sort.startsWith('-') ? 'DESC' : 'ASC';

  // 白名单验证
  if (!ALLOWED_SORT_FIELDS.includes(field)) {
    return null;
  }

  return { field, dir };
}

/**
 * 验证分页参数
 */
export function validatePaginationParams(params: any): {
  page: number;
  limit: number;
  error?: string;
} {
  const page = parseInt(params.page);
  const limit = parseInt(params.limit);

  if (isNaN(page) || page < 1) {
    return { page: 1, limit: 20, error: 'Invalid page number' };
  }

  if (isNaN(limit) || limit < 1 || limit > 100) {
    return { page: 1, limit: 20, error: 'Limit must be between 1 and 100' };
  }

  return { page, limit };
}

/**
 * 验证ID参数
 */
export function validateIdParam(id: string): number | null {
  const numId = parseInt(id);
  if (isNaN(numId) || numId < 1) {
    return null;
  }
  return numId;
}

/**
 * 清理字符串输入（防止XSS）
 */
export function sanitizeString(input: string): string {
  return input
    .replace(/[<>]/g, '')  // 移除尖括号
    .trim()
    .slice(0, 1000);       // 限制长度
}

/**
