// 在 buildPaginationQuery 函数中使用验证
import { validateSortParam } from '../utils/validation';

export function buildPaginationQuery(params: PaginationParams): {
  limit: number;
  offset: number;
  orderBy: string;
} {
  const limit = Math.min(params.limit || 50, 100);
  const page = Math.max(params.page || 1, 1);
  const offset = (page - 1) * limit;

  let orderBy = 'created_at DESC';

  // ✅ 使用白名单验证
  if (params.sort) {
    const validated = validateSortParam(params.sort);
    if (validated) {
      orderBy = `${validated.field} ${validated.dir}`;
    }
  }

  return { limit, offset, orderBy };
}
