/**
 * 请求验证中间件
 */
import { FastifyRequest, FastifyReply } from 'fastify';
import { validateIdParam, validatePaginationParams } from '../utils/validation';

export async function validateIterationId(
  request: FastifyRequest,
  reply: FastifyReply
) {
  const { id } = request.params as { id: string };
  const validatedId = validateIdParam(id);

  if (!validatedId) {
    return reply.code(400).send({
      success: false,
      error: { message: 'Invalid iteration ID', code: 'INVALID_PARAMS' }
    });
  }

  // 将验证后的ID附加到请求
  (request as any).validatedId = validatedId;
}

export async function validatePagination(
  request: FastifyRequest,
  reply: FastifyReply
) {
  const query = request.query as any;
  const validated = validatePaginationParams(query);

  if (validated.error) {
    return reply.code(400).send({
      success: false,
      error: { message: validated.error, code: 'INVALID_PARAMS' }
    });
  }

  (request as any).validatedPagination = {
    page: validated.page,
    limit: validated.limit
  };
}
```

